var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하!!","JPN":"猊下！！","ENG":"Your Eminence!!","TWN":"主教！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"정신 차리세요……!! 예하!!","JPN":"しっかりしてください……！！　猊下！！","ENG":"Wake up...! Your Eminence!!","TWN":"你醒醒……！！主教！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"이…… 목소리는…… 비블리데?","JPN":"この……声は……ビブリデ？","ENG":"That voice... Is that you... Biblide?","TWN":"這……聲音是……布莉黛？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하, 아무 말씀도 하시지 마세요!","JPN":"猊下、言葉を発してはなりません！","ENG":"Your Eminence, please do not talk!","TWN":"主教，你不要說話！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"지금 지혈해 드리겠습니다! 조금만 참으세요!","JPN":"今止血します！　もう少し我慢してください！","ENG":"I will try to stop the bleeding! Stay with me!","TWN":"我立刻替你止血！你忍耐一下！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"비블리데, 나의 딸아…….","JPN":"ビブリデ、我が娘よ……","ENG":"Oh Biblide... My daughter...","TWN":"布莉黛，我的女兒……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"그동안…… 내가 너무 너를…….","JPN":"これまで……私は君に……","ENG":"I apologize for... not paying enough attention...","TWN":"過去……我對你太……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"말씀하지 마세요!","JPN":"お話しになってはいけません！","ENG":"Please, stop talking!","TWN":"別說了！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"부디…… 그 어리석은 녀석을……","JPN":"どうか……あの愚かな子を……","ENG":"Please... save that foolish...","TWN":"求你……救救那傻小子……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제게…… 제게 또 그런 부탁하지 마세요, 제발……!","JPN":"私に……私にまたそんなことを頼まないでください、お願い……！","ENG":"Please...! Do not ask that of me...!","TWN":"不要……我做不到，拜託……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"그, 그 맹신은…… 구원은커녕…… 파멸만이…….","JPN":"そ、その盲信は……救いはおろか……破滅だけが……","ENG":"H-his blind faith... only destruction... not salvation...","TWN":"盲從……只會帶來毀滅……不會帶來救贖……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"지금이라도…… 주의 품으로……!","JPN":"今でも……主の元へ……！","ENG":"It is not too late... the Lord's arms...!","TWN":"快將他……帶回天主的……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제발, 제발……! 아직 한 번도 아버지라고 불러드린 적 없는데……!","JPN":"お願い、お願いします……！　まだ一度も父とお呼びできていません……！","ENG":"Please...! I still have not had the chance to call you father even once...!","TWN":"拜託，你不要死……！我都還沒叫過你一聲爸爸……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"죄송해요, 죄송해요…… 그러니까……!!","JPN":"ごめんなさい、ごめんなさい……だから……！！","ENG":"I am sorry... So please...!!","TWN":"對不起，對不起……我拜託你……！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하?","JPN":"猊下？","ENG":"Your Eminence?","TWN":"主教？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하……!! 예하!!","JPN":"猊下……！！　猊下！！","ENG":"Your Eminence...! Eminence!!","TWN":"主教……！！主教！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……이건?","JPN":"……これは？","ENG":"Huh?","TWN":"……這是？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"학회의 하수인과 함께 지하 밑바닥에 다다랐을 때……","JPN":"学会の末端と一緒に地下の底にたどり着いた時……","ENG":"When I got to the bottom of the basement with the Society's servants...","TWN":"我和學會的手下一起抵達地下道時……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L34_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그것은…… 분명 침식체와는 격이 다른 존재였습니다.","JPN":"それは……確かに侵食体とは格の違う存在でした。","ENG":"It was... clearly a different entity than that of a C.O.","TWN":"那個存在……完全和侵蝕體不同層級。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"학회는 그것을 역병의……","JPN":"学会はそれを疫病の……","ENG":"The Society called it the Plague of...","TWN":"學會將其稱為瘟疫的……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"……막아야 합니다!!","JPN":"……止めるべきです！！","ENG":"We must prevent─!!","TWN":"……不能讓他們得逞！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"자네는 부끄럽지도 않은가!!","JPN":"君は恥ずかしくないのか！！","ENG":"Have you no shame?!","TWN":"你都不覺得丟人嗎！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"주께서는 스스로 돕는 자를 돕는다고……","JPN":"天は自ら助くる者を助くと……","ENG":"The Lord said He helps those who help themselves, but...","TWN":"都說天助自助者……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"……찾아 낼 겁니다.","JPN":"……探し出します。","ENG":"I will find a way.","TWN":"……我一定會找到！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"모든 이가 <color=#ffd34c>신성</color>에 도달하는 방법을……","JPN":"すべての者が<color=#ffd34c>神聖</color>に到達する方法を……","ENG":"A way for all to reach <color=#ffd34c>Divinity</color>...","TWN":"讓所有人達到<color=#ffd34c>神聖</color>的方法……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"이미 더럽혀진 손입니다! 구원을 위해서라면 얼마든지요……!!","JPN":"私の手はすでに汚れています！　救いのためならいくらでも……！！","ENG":"My hands are already tainted! Anything for salvation...!!","TWN":"這已經是一雙弄髒的手！只要能夠得到救贖，無論要做什麼……！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"이, 이런……!! 불경한……!!","JPN":"こ、この……！！　不敬な……！！","ENG":"B-blasphemous!","TWN":"你這個……！！不敬虔……！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"절 거둬주신 걸…… 후회하진 않으십니까?","JPN":"私を引き取ったことを……後悔してはいませんか？","ENG":"Do you regret... taking me in?","TWN":"你不後悔……收留我嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"이게 뭔데? 뭐가 이리 지직거려?","JPN":"何、これ？　なんで雑音だらけなんだよ？","ENG":"What's this? Why does it keep crackling up?","TWN":"這是怎樣？怎麼一直有雜音？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성황청의 모든 행정 절차는 기록으로 남기게 되어 있죠.","JPN":"聖皇庁のすべての行政的な手続きは記録に残すようになっています。","ENG":"The Holy Curia requires that all procedures be recorded.","TWN":"這是為方便記錄聖皇廳的所有行政訴訟而錄的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"충격으로 심각하게 훼손되어 있지만, 그 자가 예하를 살해했다는 명백한 증거입니다.","JPN":"衝撃で酷く痛んでいますが、あの人が猊下を殺したというはっきりとした証拠です。","ENG":"Although the device is severely damaged by the impact, it is indisputable evidence that \\"he\\" murdered his Eminence.","TWN":"只是因為受到衝擊而嚴重毀損，但已經足以作為他殺害主教的有力證據。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"신부님이 정말로…….","JPN":"本当に神父様が……","ENG":"Then Father Constantine really did...","TWN":"神父真的……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"돌이켜보면, 전에도 기회는 있었습니다.","JPN":"振り返ってみると、前にもチャンスはありました。","ENG":"Looking back, this was not \\"his\\" first attempt.","TWN":"現在回想起來，我原本有機會可以阻止的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하의 제안대로 더 빨리 조사에 착수했더라면 이런 일이 생기지 않았을 수도 있었겠죠.","JPN":"猊下の提案どおり、もっと早く調査を始めていたならこんなことにはならなかったかもしれません。","ENG":"Perhaps if I had begun the investigation sooner, as his Eminence suggested, this tragedy could have been avoided.","TWN":"若我接受主教的委託盡快著手調查，很可能就不會發生這種事。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그런데…… 저는 고작 자존심 때문에 예하를…….","JPN":"ですが……私はプライドのせいで猊下を……","ENG":"But... my stubbornness...","TWN":"我卻……因為區區的自尊心而害主教……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"용서할 수 없습니다. 그 남자도, 저 자신도.","JPN":"許せません。あの男も、私自身も。","ENG":"I cannot forgive myself, or \\"him\\".","TWN":"我無法原諒那男的，也無法原諒我自己。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"반드시 베네딕트를 찾아내어 죗값을 치르게 할 겁니다.","JPN":"必ずベネディクトを探し出し、償わせます。","ENG":"I shall make Benedict repent for his sins.","TWN":"我一定要找到本尼迪克特，讓他付出應有的代價！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"……칫.","JPN":"……ちっ。","ENG":"Tch...","TWN":"……嘖。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"반드시 따라오라는 말은 안 하겠습니다","JPN":"必ずついて来いとは言いません。","ENG":"I will not ask you to follow me.","TWN":"我不會要求你們和我一起，"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오히려 동료였던 자를 심판할 각오가 없다면 그만두세요.","JPN":"むしろ仲間だった者を審判する覚悟がなければやめてください。","ENG":"If you are hesitant about bringing judgment to a fellow colleague, I suggest you quit now.","TWN":"若是你們沒有做好審判前同事的心理準備，我反而還要勸你們別參與這次的任務。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……좋아요.","JPN":"……いいですわ。","ENG":"All right.","TWN":"……好。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"저는 루체 자매님을 도와 콘스탄틴 신부님을 찾겠어요.","JPN":"私はシスター・ルーチェを手伝ってコンスタンティン神父を探します。","ENG":"I will help you find Father Constantine, Sister Luce.","TWN":"我願意幫助露契姊妹找到康斯坦丁神父。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"하지만 그건 신부님을 심판하기 위해서가 아니에요.","JPN":"でもそれは神父様を審判するためではありません。","ENG":"But it is not for bringing judgment to Father.","TWN":"但我不是為了要審判神父，"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"신부님의 이야기를 듣기 위해서죠.","JPN":"神父様の話を聞くためです。","ENG":"It is to hear Father's side of the story.","TWN":"而是為了要聽他的說法。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시스터 넬슨……!","JPN":"シスターネルソン……！","ENG":"Sister Nelson...!","TWN":"尼爾森姊妹……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……의심할 수 없을 때까지 의심해야 한다.","JPN":"……疑えなくなるまで疑え。","ENG":"\\"Doubt until thou cannot doubt any more.\\"","TWN":"……凡事都要抱持懷疑的態度。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"요한 추기경께서 가르쳐 주셨잖아요?","JPN":"ヨハン枢機卿が教えてくださったじゃないですか。","ENG":"Isn't this what Cardinal Johan taught us?","TWN":"這不是約翰樞機主教教的嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그러니까 전 신부님께 직접 이야기를 듣기 전까지는 <color=#ffd34c>사정</color>이 있었을 거라고 의심하겠어요.","JPN":"ですから私は神父様に直接話を聞くまでは<color=#ffd34c>事情</color>があったのではと疑います。","ENG":"I will reserve all judgment until I've heard Father speak in person, and I suspect that he had his <color=#ffd34c>reasons</color>.","TWN":"所以在聽到神父自己的說法之前，我都會懷疑他是有<color=#ffd34c>苦衷</color>的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"결정은…… 신부님의 이야기를 들은 후에.","JPN":"決定は……神父様の話を聞いた後に。","ENG":"The decision... will be made after hearing his side.","TWN":"而定論……就等聽到神父的說法後再決定。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"역시 당신은 선량하군요. 심의회에 어울리지 않을 만큼.","JPN":"やはりあなたは優しいですね。審議会には合わないほどに。","ENG":"You are far too naive, Sister. Perhaps enough to be unfit for the Investigation Council.","TWN":"你果然很善良，善良到不適合議會。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"죄, 죄송해요, 루체 자매님.","JPN":"ご、ごめんなさい、シスター・ルーチェ。","ENG":"M-my apologies, Sister Luce.","TWN":"抱…抱歉，露契姊妹。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 각오도 느껴지는군요.","JPN":"ですが覚悟も感じられます。","ENG":"However, I do sense your determination.","TWN":"不過我有感受到你的決心。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그럼, 그 자를 찾아내는 것까지는 합의가 되었다고 생각해도 되겠습니까?","JPN":"それでは、あの人を探し出すことまでは合意したと思ってもいいでしょうか。","ENG":"Then, may I say that we have reached an agreement on finding him?","TWN":"那我可以認為你願意和我一起把他找出來嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네. 저는 그걸로 만족해요. 감사합니다, 루체 자매님.","JPN":"はい。私はそれで満足ですわ。ありがとうございます、シスター・ルーチェ。","ENG":"Yes. I think so, Sister Luce. Thank you.","TWN":"是的，我沒有其他意見，謝謝你，露契姊妹。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"어이, 꼰대. 누굴 까먹지 않았어?","JPN":"おい、ばばあ。一人忘れてない？","ENG":"Hey, Snob. Aren't ya forgetting someone?","TWN":"喂，四眼姊姊，你是不是忘記誰啦？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"잊지 않았습니다.","JPN":"忘れていません。","ENG":"I did not forget.","TWN":"我沒忘。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시스터 루퍼에게는 좀 더 특별한 임무를 맡길 예정입니다만.","JPN":"シスタールーパーにはもっと特別な任務をお願いする予定です。","ENG":"I am planning to entrust Sister Looper with a \\"special mission\\".","TWN":"我打算給洛珀姊妹一個更特別的任務。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"특별한 임무?","JPN":"特別な任務？","ENG":"A special mission?","TWN":"特別的任務？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"가장 가까운 곳에서 시스터 넬슨의 곁을 지키는 것.","JPN":"一番近くでシスターネルソンを守ること。","ENG":"You are to stand by Sister Nelson's side and protect her.","TWN":"就是貼身保護尼爾森姊妹。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그것이 당신의 임무입니다, 시스터 루퍼.","JPN":"それがあなたの任務です、シスタールーパー。","ENG":"That is your mission, Sister Looper.","TWN":"這就是你的任務，洛珀姊妹。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"쳇. 그럼 클로디아 가는 길에 나도 따라 가야 하잖아.","JPN":"ちっ。じゃあ、クラウディアが行くところに付いて行かないとダメじゃん。","ENG":"Tch! But that means I have to go wherever Claudia goes.","TWN":"嘖，那意思不是一樣？克勞迪婭去哪我就要去哪。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그런데…… 루체 자매님.","JPN":"でも……シスター・ルーチェ。","ENG":"But, Sister Luce...","TWN":"不過……露契姊妹。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"신부님을 찾는다고 해도 어디부터 시작해야 할까요?","JPN":"神父様を探すとしても、どこから始めればいいのでしょう？","ENG":"Where do we even start looking for Father Constantine?","TWN":"說是說要找到神父，但我們要從何找起呢？"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그건 걱정하지 마세요, 시스터 넬슨.","JPN":"それは心配いりません、シスターネルソン。","ENG":"No need to worry about that, Sister Nelson.","TWN":"放心吧，尼爾森姊妹。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기적심의회는 여러 외부 세력과 협력 관계를 유지하고 있으니까요.","JPN":"奇跡審議会は様々な外部勢力と協力関係を維持していますので。","ENG":"The Miracle Investigation Council maintains cooperative relationships with a variety of external parties.","TWN":"奇蹟議會和許多外界的勢力都保持著合作關係。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"우선, 두 사람은 그 주소로 찾아가 <color=#ffd34c>버넷</color> 경과 만나고 오세요.","JPN":"まず、お二人はその住所を訪ねて<color=#ffd34c>バーネット</color>卿に会ってください。","ENG":"First, both of you should go to this address and meet with Sir <color=#ffd34c>Burnett</color>.","TWN":"你們先照著這個地址去見<color=#ffd34c>伯內</color>。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 외 자세한 정보는 나중에 서면으로 보내드리겠습니다.","JPN":"その他の詳しい情報は後で書面にてお送りします。","ENG":"I shall send you further details later in writing.","TWN":"其他詳細的內容，我之後會再寄信給你們。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"버넷 경? 뭐 하는 작잔데?","JPN":"バーネット卿？　何する人なんだよ？","ENG":"\\"Sir Burnett\\"? Who's he?","TWN":"伯內？找他要幹嘛？"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이 분야의 프로페셔널이시죠.","JPN":"この分野のプロフェッショナルです。","ENG":"A professional in this area.","TWN":"因為他是這個領域的專家。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"사람을 찾는 것도 그리고…… 잡는 것도.","JPN":"人を探すことも、そして……捕まえることも。","ENG":"He is an expert in finding... and catching people.","TWN":"他很擅長找人……也很擅長抓人。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"엄격한 분이시지만, 저희 사정을 설명하면 기꺼이 협조 해주실 겁니다.","JPN":"厳しい方ですが、事情を説明すれば喜んで協力してくれるでしょう。","ENG":"Though he may be strict, he will cooperate once he hears of our situation.","TWN":"雖然不太好相處，但相信聽完我們的緣由後，他會很樂意協助我們的。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"알겠습니다. 루퍼 자매님과 함께 다녀올게요.","JPN":"わかりましたわ。シスター・ルーパーと一緒に行ってきます。","ENG":"Understood. Sister Looper and I will go there immediately.","TWN":"好的，那我們出發囉。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……좋습니다.","JPN":"……いいでしょう。","ENG":"Very well.","TWN":"……很好，"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그럼, 제 9호 기적심의회. 새로운 성무에 착수하겠습니다.","JPN":"それでは、第9号奇跡審議会。新しい聖務を始めます。","ENG":"Then, the Miracle Investigation Council 9 will begin a new sacred mission.","TWN":"第9奇蹟議會，正式著手新的聖務。"},"stage":{"bg":"VATICAN_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};